<script>
import axios from 'axios'
var loc = window.location.pathname.split('/').slice(-1)[0];

export default {
	name: "App",
	metaInfo: {
		title: "card.syui.ai",
	},
	data () {
		return {
			card: null,
			cards: null,
			loc: window.location.pathname.split('/').slice(-1)[0],
			id: null,
			record: null,
			url: null,
			user: null,
			userid: null,
			ucard: null,
			status: null,
			premium: false,
			premium_text: null,
			rcards: null,
		}
	},
	mounted() {
		if (loc === 'owner'){
			axios
				.get("/json/card.json")
				.then(response => (this.rcards = response));
		} else {
		axios.get("https://cors-card.herokuapp.com/https://api.syui.ai/users?itemsPerPage=255",{ crossdomain: true })
			.then(response => { 
			this.record = response;
			this.id = this.record.data.find((v) => v.username == loc).id;
			let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=255";
			if (loc.length > 1){
				axios
					.get(url,{ crossdomain: true })
					.then(response => (this.cards = response));
			}
			
		})
		.catch(error => console.log(error));
	}},
	methods: {
		submit() {
			let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=255";
			axios
				.get(url,{ crossdomain: true })
				.then(response => (this.cards = response));
				axios
					.get("https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id,{ crossdomain: true })
					.then(response => (this.user = response));
		},
		page() {
			this.id = this.record.data.find((v) => v.username == this.userid).id;
			let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=255";
			axios
				.get(url,{ crossdomain: true })
				.then(response => (this.ucard = response));
				//window.location.href = '/' + this.user;
		},
		sort(){
			if (this.premium) {
				this.premium = false;
				let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=255";
				axios
					.get(url,{ crossdomain: true })
					.then(response => (this.cards = response));
			}
			return this.cards.data.sort((a, b) => {
				return b.cp - a.cp;
			});
		},
		sortcard(){
			if (this.premium) {
				this.premium = false;
				let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=255";
				axios
					.get(url,{ crossdomain: true })
					.then(response => (this.cards = response));
			}
			return this.cards.data.sort((a, b) => {
				return b.card - a.card;
			});
		},
		cardpremium(){
			return this.cards.data.sort((a,b) => {
				this.premium = true;
				if (a.card >= 1 && a.cp < 50 ) {
					a.url = "[unavailable] rare cp < 50";
					return b.card - a.card;
				} else if (a.card === 15) {
					a.url = "[unavailable] card == 15";
				} else if (b.card === 0 && b.cp > 350) {
					a.url = "[unavailable] normal cp > 350";
					return b.card - a.card;
				} else if (a.cp === 0) {
					a.url = "[unavailable] cp == 0";
					return b.card - a.card;
				} else if (a.card === 0 && a.status === "super") {
					a.url = "[unavailable] normal == super";
					return b.card - a.card;
				} else {
					a.url = null;
					a.card = null;
					return
				}
			});
		}
	}
}
</script>

